import React, { useState, useRef } from 'react';
import Wavify from 'react-wavify';
import '../styles/Home.css';

function Home() {
  const [isUserSpeaking, setIsUserSpeaking] = useState(false);
  const [isCoachSpeaking, setIsCoachSpeaking] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [audioBlob, setAudioBlob] = useState(null);
  const mediaRecorderRef = useRef(null);

  const handleRecord = async () => {
    if (isRecording) {
      // Stop recording
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    } else {
      // Start recording
      if (navigator.mediaDevices && navigator.mediaDevices.getUserMedia) {
        try {
          const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
          mediaRecorderRef.current = new MediaRecorder(stream);

          const audioChunks = [];
          mediaRecorderRef.current.ondataavailable = (event) => {
            audioChunks.push(event.data);
          };

          mediaRecorderRef.current.onstop = () => {
            const audioBlob = new Blob(audioChunks, { type: 'audio/wav' });
            setAudioBlob(audioBlob);
            stream.getTracks().forEach(track => track.stop()); // Stop all audio tracks
          };

          mediaRecorderRef.current.start();
          setIsRecording(true);
        } catch (err) {
          console.error("Error accessing audio media:", err);
        }
      } else {
        alert("Audio recording is not supported in this browser.");
      }
    }
  };

  // const handleUserSpeak = () => {
  //   setIsUserSpeaking(true);

  //   // Simulate user speaking for 3 seconds, then coach responds after 5 seconds
  //   setTimeout(() => {
  //     setIsUserSpeaking(false);
  //     setIsCoachSpeaking(true);

  //     // Simulate coach speaking duration
  //     setTimeout(() => {
  //       setIsCoachSpeaking(false);
  //     }, 10000); // Coach speaks for 5 seconds
  //   }, 3000); // User speaks for 3 seconds
  // };

  const sendAudioToBackend = async () => {
    if (audioBlob) {
      const formData = new FormData();
      formData.append('audio', audioBlob, 'user_audio.wav');

      try {
        const response = await fetch('/api/chat-to-coach', {
          method: 'POST',
          body: formData
        });

        if (response.ok) {
          const result = await response.json();
          console.log("Audio response:", result);
          // Here you can handle playing the returned audio response
        } else {
          console.error("Failed to send audio to the backend.");
        }
      } catch (error) {
        console.error("Error sending audio to backend:", error);
      }
    }
  };

  return (
    <div className="home-container">
      <div className="animated-background"></div>
      <h1 className="home-heading patrick-hand-regular">26Coach</h1>
      <h3 className="home-subheading patrick-hand-regular">THE MARATHON COACH THAT LIVES IN YOUR AIRPODS</h3>
      <div className="cta-container">
        <button 
          onClick={handleRecord} 
          className={`cta-button ${isRecording ? 'pulse' : ''}`}
        >
          {isRecording ? 'Recording...' : 'Speak to 26Coach'}
        </button>
      </div>

      {audioBlob && (
        <button onClick={sendAudioToBackend} className="send-audio-button">
          Send Recording to Coach
        </button>
      )}

      <div className="wave-container">
        {isCoachSpeaking && (
          <Wavify 
            fill="#DE7C7D"
            paused={false}
            options={{
              height: 30,
              amplitude: 25,
              speed: 0.6,
              points: 4,
            }}
          />
        )}
      </div>
    </div>
  );
}

export default Home;
